const costs = $('Cost spike check').first().json || {};
const loops = $('Loop storm check').first().json || {};
const drifters = $('Agent drift check').all().map(i => i.json).filter(r => r.agent_name && r.is_drifting);
const volume = $('Memo volume spike').first().json || {};

const anomalies = [];
if (costs.is_spike) anomalies.push({ type: 'cost_spike', severity: 'critical',
  detail: `Cost ${costs.spike_ratio}x normal (${costs.last_hour_cost} vs avg ${costs.avg_cost})` });
if (loops.is_loop_storm) anomalies.push({ type: 'loop_storm', severity: 'critical',
  detail: `${loops.loops_last_30min} loops + ${loops.errors_last_30min} errors in 30min` });
if (volume.is_volume_spike) anomalies.push({ type: 'memo_volume_spike', severity: 'high',
  detail: `${volume.last_hour_memos} memos vs avg ${volume.avg_memos}` });
for (const d of drifters) anomalies.push({ type: 'agent_drift', severity: 'high',
  agent: d.agent_name, detail: `${d.today_rate}% vs ${d.week_avg_rate}% week avg` });

if (anomalies.length === 0) return [{ json: { no_anomalies: true } }];

const critical = anomalies.filter(a => a.severity === 'critical');
const report = anomalies.map(a => `• [${a.severity.toUpperCase()}] ${a.type}: ${a.detail}`).join('\n');
return [{ json: { anomalies, critical_count: critical.length,
  report, no_anomalies: false } }];
